/**
 * One update from a live agent-text-stream watch. `Chunk.text` is an
 * incremental fragment; `Finished.text` is the complete transcript.
 */
sealed class AgentStreamUpdateFfi {
    
    data class Chunk(
        val `seq`: kotlin.ULong, 
        val `text`: kotlin.String) : AgentStreamUpdateFfi() {
        companion object
    }
    
    data class Finished(
        val `text`: kotlin.String, 
        val `transcriptHashHex`: kotlin.String, 
        val `chunkCount`: kotlin.ULong) : AgentStreamUpdateFfi() {
        companion object
    }
    
    data class Failed(
        val `message`: kotlin.String) : AgentStreamUpdateFfi() {
        companion object
    }
    

    
    companion object
}

/**
 * @suppress
 */
public object FfiConverterTypeAgentStreamUpdateFfi : FfiConverterRustBuffer<AgentStreamUpdateFfi>{
    override fun read(buf: ByteBuffer): AgentStreamUpdateFfi {
        return when(buf.getInt()) {
            1 -> AgentStreamUpdateFfi.Chunk(
                FfiConverterULong.read(buf),
                FfiConverterString.read(buf),
                )
            2 -> AgentStreamUpdateFfi.Finished(
                FfiConverterString.read(buf),
                FfiConverterString.read(buf),
                FfiConverterULong.read(buf),
                )
            3 -> AgentStreamUpdateFfi.Failed(
                FfiConverterString.read(buf),
                )
            else -> throw RuntimeException("invalid enum value, something is very wrong!!")
        }
    }

    override fun allocationSize(value: AgentStreamUpdateFfi) = when(value) {
        is AgentStreamUpdateFfi.Chunk -> {
            // Add the size for the Int that specifies the variant plus the size needed for all fields
            (
                4UL
                + FfiConverterULong.allocationSize(value.`seq`)
                + FfiConverterString.allocationSize(value.`text`)
            )
        }
        is AgentStreamUpdateFfi.Finished -> {
            // Add the size for the Int that specifies the variant plus the size needed for all fields
            (
                4UL
                + FfiConverterString.allocationSize(value.`text`)
                + FfiConverterString.allocationSize(value.`transcriptHashHex`)
                + FfiConverterULong.allocationSize(value.`chunkCount`)
            )
        }
        is AgentStreamUpdateFfi.Failed -> {
            // Add the size for the Int that specifies the variant plus the size needed for all fields
            (
                4UL
                + FfiConverterString.allocationSize(value.`message`)
            )
        }
    }

    override fun write(value: AgentStreamUpdateFfi, buf: ByteBuffer) {
        when(value) {
            is AgentStreamUpdateFfi.Chunk -> {
                buf.putInt(1)
                FfiConverterULong.write(value.`seq`, buf)
                FfiConverterString.write(value.`text`, buf)
                Unit
            }
            is AgentStreamUpdateFfi.Finished -> {
                buf.putInt(2)
                FfiConverterString.write(value.`text`, buf)
                FfiConverterString.write(value.`transcriptHashHex`, buf)
                FfiConverterULong.write(value.`chunkCount`, buf)
                Unit
            }
            is AgentStreamUpdateFfi.Failed -> {
                buf.putInt(3)
                FfiConverterString.write(value.`message`, buf)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }
}





